import requests

class PaperSummarizer:
    def __init__(self, api_key):
        self.api_key = api_key
        self.api_url = "https://api.claude.ai/summarize"

    def summarize_paper(self, paper_text):
        headers = {
            "Authorization": f"Bearer {self.api_key}",
            "Content-Type": "application/json"
        }
        data = {
            "text": paper_text,
            "summary_length": "short"
        }
        response = requests.post(self.api_url, headers=headers, json=data)
        if response.status_code == 200:
            return response.json().get("summary")
        else:
            raise Exception("Error summarizing paper: " + response.text)

    def ask_question(self, summary, question):
        headers = {
            "Authorization": f"Bearer {self.api_key}",
            "Content-Type": "application/json"
        }
        data = {
            "context": summary,
            "question": question
        }
        response = requests.post(self.api_url + "/ask", headers=headers, json=data)
        if response.status_code == 200:
            return response.json().get("answer")
        else:
            raise Exception("Error asking question: " + response.text)

def main():
    api_key = "your_api_key_here"
    summarizer = PaperSummarizer(api_key)

    paper_text = input("Enter the text of the paper: ")
    summary = summarizer.summarize_paper(paper_text)
    print("Summary:", summary)

    while True:
        question = input("Ask a question about the summary (or type 'exit' to quit): ")
        if question.lower() == 'exit':
            break
        answer = summarizer.ask_question(summary, question)
        print("Answer:", answer)

if __name__ == "__main__":
    main()

